/**
 * Cross-process pointer to the active Studio session for this agent (or, when
 * the agent exposes no session id, this worktree). `createStudioSession` writes
 * it on launch; `openStudioTo` reads it to decide what to do.
 *
 * The model is deliberately binary:
 *   - file present => a session is believed live. `openStudioTo` navigates to it
 *     and NEVER opens a second window while a record exists. If the tab does not
 *     answer the navigation it gates (asks the user) rather than spawning a
 *     duplicate.
 *   - file absent  => no session. `openStudioTo` opens a fresh window.
 *
 * The file is REMOVED (not stamped) the moment the window is gone: the event
 * poller clears it on a tab close (after the refresh grace period) and on a
 * deliberate end ("return to agent & close" / `closeStudio`). So a cleanly
 * closed or ended session leaves no record, and the next open is a silent fresh
 * window. Only an unwitnessed disappearance (crash, sleep, a close no poller
 * saw) leaves a stale record behind, which is exactly the case that should gate.
 *
 * Recovery from a stale record is explicit: `clearActiveStudioSession(id,
 * { force: true })` (exposed via the `clearStudioSession` command) removes the
 * pointer so the next `openStudioTo` opens fresh.
 *
 * Scope key: the host coding agent's stable session id when exposed, else a hash
 * of `process.cwd()`. Two agents sharing one worktree keep separate records.
 * Single slot per scope: a second `createStudioSession` in the same scope
 * replaces the first. The browser tab can outlive the CLI process, so reads do
 * NOT check pid liveness; the navigation layer handles that.
 *
 * Only STABLE per-session ids are used (the file is a cross-process handshake,
 * so the writer and a later reader must resolve the same scope). Per-request ids
 * (e.g. `CURSOR_TRACE_ID`) are deliberately excluded.
 *
 * Mirrors `activePreviewSession.ts` shape and atomicity guarantees.
 */
interface ActiveStudioSession {
    sessionId: string;
    serviceUrl: string;
    pid: number;
    startedAt: string;
}
export declare function writeActiveStudioSession(session: Omit<ActiveStudioSession, "pid" | "startedAt">): void;
/**
 * Remove the active-session pointer. The window is gone, so the next
 * `openStudioTo` opens a fresh one instead of trying to reach a dead tab.
 *
 * No-op unless the record still names `sessionId` (we never clear a different
 * session's pointer). The event poller passes no `force`, so it additionally
 * defers to a newer owner: it only clears when THIS process wrote the record or
 * the writer is no longer alive, which stops a stale poller from deleting a
 * pointer a newer process just re-bound. A deliberate clear (`closeStudio`, the
 * `clearStudioSession` recovery command) passes `force: true` to skip that pid
 * guard while still matching on `sessionId`.
 */
export declare function clearActiveStudioSession(sessionId: string, opts?: {
    force?: boolean;
}): boolean;
/**
 * Return the active Studio session for this scope, or null if none is recorded.
 * Does NOT check whether the writer process is still alive: the browser tab can
 * outlive the CLI process that created it (e.g. `openTracePlan.js` exits on
 * confirm/cancel but the Studio tab stays open for the next iteration). The real
 * liveness check happens at the navigation layer (`navigateStudioAndAwaitAck` in
 * `openStudioTo`); when that fails, the record is cleared (on a witnessed close)
 * or left for the user to clear (on an unwitnessed disappearance).
 */
export declare function readActiveStudioSession(): ActiveStudioSession | null;
export {};
